package sequence

import (
	"database/sql"
	"strings"
	"testing"
	"time"

	"github.com/usenurge/nurgesh/internal/db"
	_ "modernc.org/sqlite"
)

func setupTestDB(t *testing.T) *sql.DB {
	t.Helper()
	d, err := sql.Open("sqlite", ":memory:")
	if err != nil {
		t.Fatal(err)
	}
	if _, err := d.Exec(db.Schema); err != nil {
		t.Fatal(err)
	}
	return d
}

func TestMailboxFirstTouchCap(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

