		t.Fatalf("paused enrollments = %d, want 1", item.PausedEnrollments)
	}
	if item.OpenTasks != 0 {
		t.Fatalf("open tasks = %d, want 0", item.OpenTasks)
	}
	if task == nil {
		t.Fatal("expected original task to exist")
	}
}

