105вҶ’			Error string `json:"error"`
106вҶ’		}
107вҶ’		json.Unmarshal(data, &errResp)
108вҶ’		return nil, fmt.Errorf("exchange failed: %s", errResp.Error)
109вҶ’	}
110вҶ’
111вҶ’	var result exchangeResponse
112вҶ’	if err := json.Unmarshal(data, &result); err != nil {
113вҶ’		return nil, fmt.Errorf("parsing response: %w", err)
114вҶ’	}
115вҶ’	return &result, nil
116вҶ’}
