118вҶ’// RevokeToken revokes a token on the Convex backend.
119вҶ’func (c *ConvexClient) RevokeToken(token string) error {
120вҶ’	body, _ := json.Marshal(map[string]string{"token": token})
121вҶ’	resp, err := c.httpClient.Post(
122вҶ’		c.baseURL+"/api/revoke-token",
123вҶ’		"application/json",
