125вҶ’	)
126вҶ’	if err != nil {
127вҶ’		return fmt.Errorf("calling revoke-token: %w", err)
128вҶ’	}
129вҶ’	defer resp.Body.Close()
130вҶ’
131вҶ’	if resp.StatusCode != 200 {
132вҶ’		return fmt.Errorf("revoke failed with status %d", resp.StatusCode)
133вҶ’	}
134вҶ’	return nil
135вҶ’}
