52вҶ’func buildRawMessage(from string, opts SendOptions) string {
53вҶ’	var b strings.Builder
54вҶ’	b.WriteString("From: " + from + "\r\n")
55вҶ’	b.WriteString("To: " + opts.To + "\r\n")
56вҶ’	if opts.Cc != "" {
57вҶ’		b.WriteString("Cc: " + opts.Cc + "\r\n")
58вҶ’	}
59вҶ’	b.WriteString("Subject: " + opts.Subject + "\r\n")
60вҶ’	b.WriteString("MIME-Version: 1.0\r\n")
61вҶ’	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
