  1вҶ’package email
  2вҶ’
  3вҶ’import (
  4вҶ’	"database/sql"
  5вҶ’	"encoding/json"
  6вҶ’	"fmt"
  7вҶ’	"strings"
  8вҶ’	"time"
  9вҶ’
 10вҶ’	gm "google.golang.org/api/gmail/v1"
 11вҶ’)
 12вҶ’
 13вҶ’type RawMessage struct {
 14вҶ’	ID          string
 15вҶ’	Source      string
 16вҶ’	Direction   string
 17вҶ’	ThreadID    string
 18вҶ’	Subject     string
 19вҶ’	FromEmail   string
 20вҶ’	ToEmails    string // JSON array
 21вҶ’	CcEmails    string // JSON array
 22вҶ’	Date        string
 23вҶ’	Snippet     string
 24вҶ’	BodyPreview string
 25вҶ’	Labels      string // JSON array
 26вҶ’}
 27вҶ’
 28вҶ’type SyncResult struct {
 29вҶ’	Fetched  int
 30вҶ’	Stored   int
 31вҶ’	Cursor   string
 32вҶ’	Duration time.Duration
 33вҶ’}
 34вҶ’
 35вҶ’func Sync(srv *gm.Service, d *sql.DB) (*SyncResult, error) {
 36вҶ’	start := time.Now()
 37вҶ’	result := &SyncResult{}
 38вҶ’
 39вҶ’	var cursor string
 40вҶ’	d.QueryRow("SELECT sync_cursor FROM connectors WHERE id = 'gmail'").Scan(&cursor)
 41вҶ’
 42вҶ’	query := "in:sent"
 43вҶ’	if cursor == "" {
 44вҶ’		since := time.Now().AddDate(0, 0, -90).Format("2006/01/02")
 45вҶ’		query += " after:" + since
 46вҶ’	}
 47вҶ’
 48вҶ’	var pageToken string
 49вҶ’	for {
 50вҶ’		req := srv.Users.Messages.List("me").Q(query).MaxResults(100)
 51вҶ’		if pageToken != "" {
 52вҶ’			req = req.PageToken(pageToken)
 53вҶ’		}
 54вҶ’
 55вҶ’		resp, err := req.Do()
 56вҶ’		if err != nil {
 57вҶ’			return result, fmt.Errorf("listing messages: %w", err)
 58вҶ’		}
 59вҶ’
 60вҶ’		for _, msg := range resp.Messages {
 61вҶ’			result.Fetched++
 62вҶ’
 63вҶ’			if cursor != "" {
 64вҶ’				var exists int
 65вҶ’				d.QueryRow("SELECT 1 FROM emails WHERE id = ?", msg.Id).Scan(&exists)
 66вҶ’				if exists == 1 {
 67вҶ’					continue
 68вҶ’				}
 69вҶ’			}
 70вҶ’
 71вҶ’			full, err := srv.Users.Messages.Get("me", msg.Id).Format("metadata").
 72вҶ’				MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 73вҶ’			if err != nil {
 74вҶ’				fmt.Printf("  warning: skipping message %s: %v\n", msg.Id, err)
 75вҶ’				continue
 76вҶ’			}
 77вҶ’
 78вҶ’			email := parseMessage(full)
 79вҶ’			if err := StoreEmail(d, email); err != nil {
 80вҶ’				fmt.Printf("  warning: storing message %s: %v\n", msg.Id, err)
 81вҶ’				continue
 82вҶ’			}
 83вҶ’			result.Stored++
 84вҶ’		}
 85вҶ’
 86вҶ’		pageToken = resp.NextPageToken
 87вҶ’		if pageToken == "" {
 88вҶ’			break
 89вҶ’		}
 90вҶ’	}
 91вҶ’
 92вҶ’	result.Cursor = time.Now().UTC().Format(time.RFC3339)
 93вҶ’	result.Duration = time.Since(start)
 94вҶ’
 95вҶ’	d.Exec(
 96вҶ’		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
 97вҶ’		 VALUES ('gmail', 'email', ?, ?, ?)
 98вҶ’		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
 99вҶ’		result.Cursor, result.Cursor, result.Stored,
100вҶ’		result.Cursor, result.Cursor, result.Stored,
101вҶ’	)
102вҶ’
103вҶ’	return result, nil
104вҶ’}
105вҶ’
106вҶ’func StoreEmail(d *sql.DB, e *RawMessage) error {
107вҶ’	source := e.Source
108вҶ’	if source == "" {
109вҶ’		source = "gmail"
110вҶ’	}
111вҶ’	direction := e.Direction
112вҶ’	if direction == "" {
113вҶ’		direction = "outbound"
114вҶ’	}
115вҶ’
116вҶ’	isNewMessage := true
117вҶ’	var existing int
118вҶ’	err := d.QueryRow(`SELECT 1 FROM emails WHERE id = ?`, e.ID).Scan(&existing)
119вҶ’	if err == nil {
120вҶ’		isNewMessage = false
121вҶ’	} else if err != nil && err != sql.ErrNoRows {
122вҶ’		return err
123вҶ’	}
124вҶ’
125вҶ’	_, err = d.Exec(`
126вҶ’		INSERT INTO emails (id, source, direction, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
127вҶ’		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
128вҶ’		ON CONFLICT(id) DO UPDATE SET
129вҶ’			source = excluded.source,
130вҶ’			direction = excluded.direction,
131вҶ’			subject = excluded.subject,
132вҶ’			snippet = excluded.snippet,
133вҶ’			body_preview = excluded.body_preview,
134вҶ’			labels = excluded.labels,
135вҶ’			synced_at = datetime('now')`,
136вҶ’		e.ID, source, direction, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
137вҶ’		e.Date, e.Snippet, e.BodyPreview, e.Labels,
138вҶ’	)
139вҶ’	if err != nil {
140вҶ’		return err
141вҶ’	}
142вҶ’	return upsertContactsForMessage(d, source, direction, e, isNewMessage)
143вҶ’}
144вҶ’
145вҶ’func parseMessage(msg *gm.Message) *RawMessage {
146вҶ’	e := &RawMessage{
147вҶ’		ID:        msg.Id,
148вҶ’		Source:    "gmail",
149вҶ’		Direction: "outbound",
150вҶ’		ThreadID:  msg.ThreadId,
151вҶ’		Snippet:   msg.Snippet,
152вҶ’		CcEmails:  "[]",
153вҶ’		ToEmails:  "[]",
154вҶ’		Labels:    "[]",
155вҶ’	}
156вҶ’
157вҶ’	for _, h := range msg.Payload.Headers {
158вҶ’		switch h.Name {
159вҶ’		case "Subject":
160вҶ’			e.Subject = h.Value
161вҶ’		case "From":
162вҶ’			e.FromEmail = extractEmail(h.Value)
163вҶ’		case "To":
164вҶ’			e.ToEmails = emailsToJSON(h.Value)
165вҶ’		case "Cc":
166вҶ’			e.CcEmails = emailsToJSON(h.Value)
167вҶ’		case "Date":
168вҶ’			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
169вҶ’				e.Date = t.UTC().Format(time.RFC3339)
170вҶ’			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
171вҶ’				e.Date = t.UTC().Format(time.RFC3339)
172вҶ’			} else {
173вҶ’				e.Date = h.Value
174вҶ’			}
175вҶ’		}
176вҶ’	}
177вҶ’
178вҶ’	if len(msg.LabelIds) > 0 {
179вҶ’		labelsJSON, _ := json.Marshal(msg.LabelIds)
180вҶ’		e.Labels = string(labelsJSON)
181вҶ’	}
182вҶ’
183вҶ’	return e
184вҶ’}
