 50вҶ’var (
 51вҶ’	initForce     bool
 52вҶ’	initSkipHooks bool
 53вҶ’	initVerbose   bool
 54вҶ’)
 55вҶ’
 56вҶ’var rootCmd = &cobra.Command{
 57вҶ’	Use:   "nurge [directory]",
 58вҶ’	Short: "nurge вҖ” outbound that learns",
 59вҶ’	Long:  "Nurge is an outbound sales tool that learns from your sent email history.\n\nRun 'nurge <directory>' to create a new project, or 'nurge' in an empty directory to initialize it.",
 60вҶ’	RunE:  runInit,
 61вҶ’}
 62вҶ’
 63вҶ’var versionCmd = &cobra.Command{
 64вҶ’	Use:         "version",
 65вҶ’	Short:       "Print the version of nurge",
 66вҶ’	Annotations: map[string]string{"skipAuth": "true"},
 67вҶ’	Run: func(cmd *cobra.Command, args []string) {
 68вҶ’		fmt.Printf("nurge %s (commit: %s, built: %s)\n", buildVersion, buildCommit, buildDate)
 69вҶ’	},
 70вҶ’}
 71вҶ’
 72вҶ’// runInit is the shared init logic used by both the root command and the hidden init alias.
 73вҶ’func runInit(cmd *cobra.Command, args []string) error {
 74вҶ’	dirCreated := ""
 75вҶ’
 76вҶ’	if len(args) == 1 {
 77вҶ’		dir := args[0]
 78вҶ’		if err := os.MkdirAll(dir, 0755); err != nil {
 79вҶ’			return fmt.Errorf("failed to create directory %s: %w", dir, err)
 80вҶ’		}
 81вҶ’		abs, err := filepath.Abs(dir)
 82вҶ’		if err != nil {
 83вҶ’			return err
 84вҶ’		}
 85вҶ’		if err := os.Chdir(abs); err != nil {
 86вҶ’			return fmt.Errorf("failed to enter directory %s: %w", dir, err)
 87вҶ’		}
 88вҶ’		dirCreated = dir
 89вҶ’	} else if !initForce {
 90вҶ’		// No directory arg: only init if current dir is empty or already initialized
 91вҶ’		empty, _ := project.IsDirEmpty(".")
 92вҶ’		alreadyInit := project.IsNurgeProject(".")
 93вҶ’		if !empty && !alreadyInit {
 94вҶ’			return cmd.Help()
 95вҶ’		}
 96вҶ’	}
 97вҶ’
 98вҶ’	// Check if current directory is non-empty (unless --force)
 99вҶ’	if !initForce {
100вҶ’		empty, err := project.IsDirEmpty(".")
101вҶ’		if err != nil {
102вҶ’			return err
103вҶ’		}
104вҶ’		if !empty && !project.IsNurgeProject(".") {
105вҶ’			return fmt.Errorf("this directory isn't empty. Run: nurge <folder-name>")
106вҶ’		}
107вҶ’	}
108вҶ’
109вҶ’	opts := project.Options{
110вҶ’		SkipHooks: initSkipHooks,
111вҶ’		Force:     initForce,
112вҶ’		Verbose:   initVerbose,
113вҶ’	}
114вҶ’	if err := project.Run(opts); err != nil {
115вҶ’		return err
116вҶ’	}
117вҶ’
118вҶ’	if dirCreated != "" {
119вҶ’		fmt.Println()
120вҶ’		fmt.Printf("  Now run: cd %s\n", dirCreated)
121вҶ’		fmt.Println()
122вҶ’	}
123вҶ’
124вҶ’	return nil
125вҶ’}
126вҶ’
127вҶ’// shouldSkipAuth walks the command tree to check if any command in the
128вҶ’// chain has the skipAuth annotation. This handles cases like
129вҶ’// "nurge account login" where account has skipAuth.
130вҶ’func shouldSkipAuth(cmd *cobra.Command) bool {
131вҶ’	for c := cmd; c != nil; c = c.Parent() {
132вҶ’		if c.Annotations != nil && c.Annotations["skipAuth"] == "true" {
133вҶ’			return true
134вҶ’		}
135вҶ’	}
136вҶ’	return false
137вҶ’}
138вҶ’
139вҶ’func init() {
140вҶ’	rootCmd.AddCommand(versionCmd)
141вҶ’
142вҶ’	rootCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
143вҶ’	rootCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
144вҶ’	rootCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")
145вҶ’
146вҶ’	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
147вҶ’		// Root command (init) skips auth вҖ” it's the first thing a user runs
148вҶ’		if cmd == rootCmd ||
149вҶ’			shouldSkipAuth(cmd) ||
150вҶ’			cmd.Name() == "help" ||
151вҶ’			cmd.Name() == "completion" {
152вҶ’			return nil
153вҶ’		}
154вҶ’		_, err := account.EnsureAuth(GetConvexURL(), GetDashboardURL())
155вҶ’		return err
156вҶ’	}
157вҶ’}
158вҶ’
159вҶ’// isKnownCommand checks if name matches any registered subcommand.
160вҶ’func isKnownCommand(name string) bool {
161вҶ’	for _, c := range rootCmd.Commands() {
162вҶ’		if c.Name() == name {
163вҶ’			return true
164вҶ’		}
165вҶ’		for _, alias := range c.Aliases {
166вҶ’			if alias == name {
167вҶ’				return true
168вҶ’			}
169вҶ’		}
170вҶ’	}
171вҶ’	return name == "help" || name == "completion"
172вҶ’}
173вҶ’
174вҶ’func Execute() error {
175вҶ’	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
176вҶ’	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
177вҶ’	// when the first arg isn't a known subcommand or flag.
178вҶ’	if len(os.Args) > 1 {
179вҶ’		first := os.Args[1]
180вҶ’		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
181вҶ’			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
182вҶ’		}
183вҶ’	}
184вҶ’	return rootCmd.Execute()
185вҶ’}
