10вҶ’// AuthFile represents the local auth credentials stored at ~/.nurge/auth.json.
11вҶ’type AuthFile struct {
12вҶ’	Token       string `json:"token"`
13вҶ’	Email       string `json:"email"`
14вҶ’	Name        string `json:"name"`
15вҶ’	CreatedAt   string `json:"created_at,omitempty"`
