26вҶ’
27вҶ’func authFilePath() (string, error) {
28вҶ’	dir, err := authDir()
29вҶ’	if err != nil {
30вҶ’		return "", err
31вҶ’	}
32вҶ’	return filepath.Join(dir, "auth.json"), nil
33вҶ’}
