35вҶ’// LoadAuth reads the auth file from ~/.nurge/auth.json.
36вҶ’func LoadAuth() (*AuthFile, error) {
37вҶ’	path, err := authFilePath()
38вҶ’	if err != nil {
39вҶ’		return nil, err
40вҶ’	}
41вҶ’	data, err := os.ReadFile(path)
42вҶ’	if err != nil {
43вҶ’		return nil, fmt.Errorf("reading auth file: %w", err)
44вҶ’	}
45вҶ’	var af AuthFile
46вҶ’	if err := json.Unmarshal(data, &af); err != nil {
47вҶ’		return nil, fmt.Errorf("parsing auth file: %w", err)
48вҶ’	}
49вҶ’	return &af, nil
50вҶ’}
51вҶ’
52вҶ’// SaveAuth writes the auth file to ~/.nurge/auth.json.
53вҶ’// Creates ~/.nurge/ with 0700 if it doesn't exist.
54вҶ’// Writes auth.json with 0600 permissions.
55вҶ’func SaveAuth(af *AuthFile) error {
56вҶ’	dir, err := authDir()
57вҶ’	if err != nil {
58вҶ’		return err
59вҶ’	}
60вҶ’	if err := os.MkdirAll(dir, 0700); err != nil {
61вҶ’		return fmt.Errorf("creating auth directory: %w", err)
62вҶ’	}
63вҶ’
