142вҶ’			var innerHooks []any
143вҶ’			for _, h := range g.hooks {
144вҶ’				innerHooks = append(innerHooks, map[string]any{
145вҶ’					"type":    "command",
146вҶ’					"command": h.command,
147вҶ’				})
148вҶ’			}
149вҶ’			entry := map[string]any{
150вҶ’				"matcher": g.matcher,
151вҶ’				"hooks":   innerHooks,
152вҶ’			}
153вҶ’			eventHooks = append(eventHooks, entry)
154вҶ’		}
