184вҶ’		m, ok := item.(map[string]any)
185вҶ’		if !ok {
186вҶ’			continue
187вҶ’		}
188вҶ’		innerHooks, ok := m["hooks"].([]any)
189вҶ’		if !ok {
190вҶ’			continue
191вҶ’		}
192вҶ’		for _, h := range innerHooks {
193вҶ’			hm, ok := h.(map[string]any)
194вҶ’			if !ok {
195вҶ’				continue
196вҶ’			}
197вҶ’			if cmd, ok := hm["command"].(string); ok && cmd == command {
198вҶ’				return true
199вҶ’			}
200вҶ’		}
201вҶ’	}
202вҶ’	return false
203вҶ’}
