239вҶ’// syncPermissionsInto ensures all RequiredPermissions are present in the
240вҶ’// given settings map (mutates in place).
241вҶ’func syncPermissionsInto(settings map[string]any) error {
242вҶ’	permissions, _ := settings["permissions"].(map[string]any)
243вҶ’	if permissions == nil {
