257вҶ’// SyncPermissions reads .claude/settings.json, adds any missing required
258вҶ’// permissions, and writes the file back. Safe to call on every session start.
259вҶ’// Returns (added, error) where added is the number of new permissions inserted.
260вҶ’func SyncPermissions() (int, error) {
261вҶ’	settingsPath := claudeSettingsPath()
262вҶ’
263вҶ’	settings := make(map[string]any)
264вҶ’	if data, err := os.ReadFile(settingsPath); err == nil {
265вҶ’		json.Unmarshal(data, &settings)
266вҶ’	} else if os.IsNotExist(err) {
267вҶ’		return 0, nil // no settings file, nothing to sync
268вҶ’	} else {
269вҶ’		return 0, err
270вҶ’	}
271вҶ’
272вҶ’	// Count before
273вҶ’	permissions, _ := settings["permissions"].(map[string]any)
274вҶ’	allowBefore := 0
275вҶ’	if permissions != nil {
276вҶ’		if a, ok := permissions["allow"].([]any); ok {
277вҶ’			allowBefore = len(a)
278вҶ’		}
279вҶ’	}
280вҶ’
281вҶ’	if err := syncPermissionsInto(settings); err != nil {
282вҶ’		return 0, err
283вҶ’	}
284вҶ’
285вҶ’	// Count after
286вҶ’	permissions, _ = settings["permissions"].(map[string]any)
287вҶ’	allowAfter := 0
288вҶ’	if a, ok := permissions["allow"].([]any); ok {
289вҶ’		allowAfter = len(a)
290вҶ’	}
291вҶ’
292вҶ’	added := allowAfter - allowBefore
293вҶ’	if added == 0 {
294вҶ’		return 0, nil // nothing changed, skip write
295вҶ’	}
296вҶ’
297вҶ’	data, err := json.MarshalIndent(settings, "", "  ")
298вҶ’	if err != nil {
299вҶ’		return 0, fmt.Errorf("marshaling settings: %w", err)
300вҶ’	}
301вҶ’	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
302вҶ’		return 0, fmt.Errorf("writing settings: %w", err)
303вҶ’	}
304вҶ’	return added, nil
