 19вҶ’}
 20вҶ’
 21вҶ’// Config is the top-level nurge configuration.
 22вҶ’type Config struct {
 23вҶ’	Version        int                        `json:"version"`
 24вҶ’	CreatedAt      string                     `json:"created_at"`
 25вҶ’	Connectors     map[string]ConnectorState  `json:"connectors"`
 26вҶ’	SetupCompleted bool                       `json:"setup_completed"`
 27вҶ’	Settings       map[string]string          `json:"settings,omitempty"`
 28вҶ’}
 29вҶ’
 30вҶ’// Path returns the path to config.json.
 31вҶ’func Path() string {
 32вҶ’	return configFile
 33вҶ’}
 34вҶ’
 35вҶ’// Default returns a new Config with default values.
 36вҶ’func Default() *Config {
 37вҶ’	return &Config{
 38вҶ’		Version:        1,
 39вҶ’		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 40вҶ’		Connectors:     make(map[string]ConnectorState),
 41вҶ’		SetupCompleted: false,
 42вҶ’	}
 43вҶ’}
 44вҶ’
 45вҶ’// Load reads config from disk.
 46вҶ’func Load() (*Config, error) {
 47вҶ’	data, err := os.ReadFile(configFile)
 48вҶ’	if err != nil {
 49вҶ’		return nil, fmt.Errorf("reading config: %w", err)
 50вҶ’	}
 51вҶ’	var cfg Config
 52вҶ’	if err := json.Unmarshal(data, &cfg); err != nil {
 53вҶ’		return nil, fmt.Errorf("parsing config: %w", err)
 54вҶ’	}
 55вҶ’	if cfg.Connectors == nil {
 56вҶ’		cfg.Connectors = make(map[string]ConnectorState)
 57вҶ’	}
 58вҶ’	return &cfg, nil
 59вҶ’}
 60вҶ’
 61вҶ’// Write saves config to disk.
 62вҶ’func Write(cfg *Config) error {
 63вҶ’	data, err := json.MarshalIndent(cfg, "", "  ")
 64вҶ’	if err != nil {
 65вҶ’		return fmt.Errorf("marshaling config: %w", err)
 66вҶ’	}
 67вҶ’	if err := os.WriteFile(configFile, data, 0644); err != nil {
 68вҶ’		return fmt.Errorf("writing config: %w", err)
 69вҶ’	}
 70вҶ’	return nil
 71вҶ’}
