 73вҶ’// SetConnector updates a connector in the config and saves.
 74вҶ’func SetConnector(id, connType, account string) error {
 75вҶ’	cfg, err := Load()
 76вҶ’	if err != nil {
 77вҶ’		return err
 78вҶ’	}
 79вҶ’	cfg.Connectors[id] = ConnectorState{
 80вҶ’		Connected:   true,
