147вҶ’func shortDate(value string) string {
148вҶ’	if value == "" {
149вҶ’		return value
150вҶ’	}
151вҶ’	if ts, err := time.Parse(time.RFC3339, value); err == nil {
152вҶ’		return ts.In(time.Local).Format("2006-01-02 15:04")
153вҶ’	}
154вҶ’	if len(value) >= 16 {
155вҶ’		return value[:16]
156вҶ’	}
157вҶ’	if len(value) >= 10 {
158вҶ’		return value[:10]
159вҶ’	}
160вҶ’	return value
161вҶ’}
162вҶ’
163вҶ’func joinRecipients(recipients []string) string {
164вҶ’	if len(recipients) == 0 {
165вҶ’		return "(unknown recipient)"
166вҶ’	}
167вҶ’	return strings.Join(recipients, ", ")
168вҶ’}
169вҶ’
170вҶ’func relativeDueStatus(value string, now time.Time) string {
171вҶ’	dueAt, err := time.Parse(time.RFC3339, value)
172вҶ’	if err != nil {
173вҶ’		return "due"
174вҶ’	}
175вҶ’
176вҶ’	delta := dueAt.Sub(now.UTC())
177вҶ’	if delta >= 0 {
178вҶ’		if delta < time.Minute {
179вҶ’			return "due soon"
180вҶ’		}
181вҶ’		if delta < time.Hour {
182вҶ’			return fmt.Sprintf("in %dm", int(delta.Round(time.Minute)/time.Minute))
183вҶ’		}
184вҶ’		if delta < 24*time.Hour {
185вҶ’			return fmt.Sprintf("in %dh", int(delta.Round(time.Hour)/time.Hour))
186вҶ’		}
187вҶ’		return fmt.Sprintf("in %dd", int(delta.Hours()/24))
188вҶ’	}
189вҶ’
190вҶ’	overdue := -delta
191вҶ’	if overdue < time.Hour {
192вҶ’		return fmt.Sprintf("%dm overdue", int(overdue.Round(time.Minute)/time.Minute))
193вҶ’	}
194вҶ’	if overdue < 24*time.Hour {
195вҶ’		return fmt.Sprintf("%dh overdue", int(overdue.Round(time.Hour)/time.Hour))
196вҶ’	}
197вҶ’	return fmt.Sprintf("%dd overdue", int(overdue.Hours()/24))
198вҶ’}
