205вҶ’	tasksSnoozeCmd.Flags().IntVar(&tasksSnoozeDays, "days", 1, "Number of days to push the task forward")
206вҶ’	tasksCancelCmd.Flags().StringVar(&tasksCancelReason, "reason", "manual cancel", "Reason recorded for cancellation")
207вҶ’	tasksCmd.AddCommand(tasksListCmd)
208вҶ’	tasksCmd.AddCommand(tasksSnoozeCmd)
209вҶ’	tasksCmd.AddCommand(tasksCancelCmd)
210вҶ’	rootCmd.AddCommand(tasksCmd)
211вҶ’}
