 94вҶ’		sentAt := timeNow()
 95вҶ’		if sendTo == "" {
 96вҶ’			return fmt.Errorf("recipient (--to) is required")
 97вҶ’		}
 98вҶ’		if sendSubject == "" {
 99вҶ’			return fmt.Errorf("subject (--subject) is required")
100вҶ’		}
101вҶ’		if sendBody == "" {
102вҶ’			return fmt.Errorf("body (--body) is required")
103вҶ’		}
104вҶ’		if sendSequence != "" {
105вҶ’			enrollment, err := sequence.ActiveEnrollmentForContact(d, selectedMailbox.ID, sendTo)
106вҶ’			if err != nil {
107вҶ’				return err
108вҶ’			}
109вҶ’			if enrollment != nil {
110вҶ’				return fmt.Errorf("%s already has an active sequence enrollment (%s)", sendTo, enrollment.ID)
111вҶ’			}
112вҶ’		}
113вҶ’		if suppression, suppressed, err := sequence.IsSuppressed(d, sendTo); err != nil {
114вҶ’			return err
115вҶ’		} else if suppressed {
116вҶ’			return fmt.Errorf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
117вҶ’		}
118вҶ’
119вҶ’		if err := sequence.CanSend(d, selectedMailbox.ID, effectiveSendType, sentAt); err != nil {
120вҶ’			return err
121вҶ’		}
122вҶ’
123вҶ’		srv, err := email.NewClient("")
124вҶ’		if err != nil {
125вҶ’			return fmt.Errorf("connecting to Gmail: %w", err)
126вҶ’		}
127вҶ’		fromAddress := strings.TrimSpace(selectedMailbox.TransportEmail)
128вҶ’		if fromAddress == "" {
129вҶ’			fromAddress = strings.TrimSpace(selectedMailbox.Email)
130вҶ’		}
131вҶ’
132вҶ’		sent, err := email.Send(srv, fromAddress, email.SendOptions{
133вҶ’			To:       sendTo,
134вҶ’			Cc:       sendCc,
135вҶ’			Subject:  sendSubject,
136вҶ’			Body:     sendBody,
137вҶ’			ThreadID: chooseSendThreadID(task),
138вҶ’		})
139вҶ’		if err != nil {
140вҶ’			return err
141вҶ’		}
142вҶ’
143вҶ’		if err := sequence.RecordSend(d, selectedMailbox.ID, effectiveSendType, sentAt); err != nil {
144вҶ’			return fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
145вҶ’		}
146вҶ’		if err := email.StoreEmail(d, &email.RawMessage{
147вҶ’			ID:        sent.MessageID,
148вҶ’			Source:    "gmail",
149вҶ’			Direction: "outbound",
150вҶ’			ThreadID:  sent.ThreadID,
151вҶ’			Subject:   sendSubject,
152вҶ’			FromEmail: fromAddress,
153вҶ’			ToEmails:  recipientsJSON(sendTo),
154вҶ’			CcEmails:  recipientsJSON(sendCc),
155вҶ’			Date:      sentAt.UTC().Format(time.RFC3339),
156вҶ’			Labels:    `["SENT"]`,
157вҶ’		}); err != nil {
158вҶ’			return fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
159вҶ’		}
160вҶ’
161вҶ’		fmt.Printf("  вң“ Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)
162вҶ’
163вҶ’		if sendSequence != "" {
164вҶ’			enrollment, nextTask, err := sequence.CreateEnrollmentAfterFirstTouch(d, sequence.EnrollmentOptions{
165вҶ’				SequenceName: sendSequence,
166вҶ’				CampaignName: sendCampaign,
167вҶ’				MailboxID:    selectedMailbox.ID,
168вҶ’				ContactEmail: sendTo,
169вҶ’				ContactName:  sendContactName,
170вҶ’				Subject:      sendSubject,
171вҶ’				InitialBody:  sendBody,
