183вҶ’			}
184вҶ’		}
185вҶ’
186вҶ’		if task != nil {
187вҶ’			nextTask, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
188вҶ’				TaskID:    task.ID,
189вҶ’				ThreadID:  sent.ThreadID,
190вҶ’				MessageID: sent.MessageID,
191вҶ’				MailboxID: selectedMailbox.ID,
192вҶ’				SentAt:    sentAt,
193вҶ’			})
