208вҶ’func init() {
209вҶ’	sendCmd.Flags().StringVar(&sendTo, "to", "", "Recipient email address")
210вҶ’	sendCmd.Flags().StringVar(&sendCc, "cc", "", "CC email address")
211вҶ’	sendCmd.Flags().StringVar(&sendSubject, "subject", "", "Email subject")
212вҶ’	sendCmd.Flags().StringVar(&sendBody, "body", "", "Email body (plain text)")
213вҶ’	sendCmd.Flags().StringVar(&sendSequence, "sequence", "", "Enroll the sent email in a built-in sequence template")
214вҶ’	sendCmd.Flags().StringVar(&sendCampaign, "campaign", "", "Optional campaign name stored on the sequence enrollment")
215вҶ’	sendCmd.Flags().StringVar(&sendTaskID, "task-id", "", "Mark a follow-up task as sent and advance the sequence")
216вҶ’	sendCmd.Flags().StringVar(&sendSendType, "send-type", "", "Override send classification (first_touch, follow_up, reply, manual)")
217вҶ’	sendCmd.Flags().StringVar(&sendContactName, "contact-name", "", "Optional prospect name stored on sequence enrollment")
