 1вҶ’package email
 2вҶ’
 3вҶ’import (
 4вҶ’	"encoding/base64"
 5вҶ’	"fmt"
 6вҶ’	"strings"
 7вҶ’
 8вҶ’	gm "google.golang.org/api/gmail/v1"
 9вҶ’)
10вҶ’
11вҶ’// SendOptions holds the fields for composing an email.
12вҶ’type SendOptions struct {
13вҶ’	To       string // recipient email
14вҶ’	Cc       string // optional CC
15вҶ’	Subject  string
16вҶ’	Body     string // plain text body
17вҶ’	ThreadID string
18вҶ’}
19вҶ’
20вҶ’type SentMessage struct {
21вҶ’	MessageID string
22вҶ’	ThreadID  string
23вҶ’}
24вҶ’
25вҶ’// Send sends an email via the Gmail API.
26вҶ’func Send(srv *gm.Service, from string, opts SendOptions) (*SentMessage, error) {
27вҶ’	if opts.To == "" {
28вҶ’		return nil, fmt.Errorf("recipient (--to) is required")
29вҶ’	}
30вҶ’	if opts.Subject == "" {
31вҶ’		return nil, fmt.Errorf("subject (--subject) is required")
32вҶ’	}
33вҶ’	if opts.Body == "" {
34вҶ’		return nil, fmt.Errorf("body (--body) is required")
35вҶ’	}
36вҶ’
37вҶ’	raw := buildRawMessage(from, opts)
38вҶ’	msg := &gm.Message{
39вҶ’		Raw: base64.URLEncoding.EncodeToString([]byte(raw)),
40вҶ’	}
41вҶ’	if opts.ThreadID != "" {
42вҶ’		msg.ThreadId = opts.ThreadID
43вҶ’	}
44вҶ’
45вҶ’	sent, err := srv.Users.Messages.Send("me", msg).Do()
46вҶ’	if err != nil {
47вҶ’		return nil, fmt.Errorf("sending email: %w", err)
48вҶ’	}
49вҶ’
50вҶ’	return &SentMessage{
51вҶ’		MessageID: sent.Id,
52вҶ’		ThreadID:  sent.ThreadId,
53вҶ’	}, nil
54вҶ’}
55вҶ’
56вҶ’func buildRawMessage(from string, opts SendOptions) string {
57вҶ’	var b strings.Builder
58вҶ’	b.WriteString("From: " + from + "\r\n")
59вҶ’	b.WriteString("To: " + opts.To + "\r\n")
60вҶ’	if opts.Cc != "" {
61вҶ’		b.WriteString("Cc: " + opts.Cc + "\r\n")
62вҶ’	}
63вҶ’	b.WriteString("Subject: " + opts.Subject + "\r\n")
64вҶ’	b.WriteString("MIME-Version: 1.0\r\n")
65вҶ’	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
66вҶ’	b.WriteString("\r\n")
67вҶ’	b.WriteString(opts.Body)
68вҶ’	return b.String()
69вҶ’}
