  1вҶ’package project
  2вҶ’
  3вҶ’import (
  4вҶ’	"encoding/json"
  5вҶ’	"fmt"
  6вҶ’	"os"
  7вҶ’	"path/filepath"
  8вҶ’	"time"
  9вҶ’)
 10вҶ’
 11вҶ’const configFile = ".nurge/config.json"
 12вҶ’
 13вҶ’// ConnectorState holds the state of a single connected service.
 14вҶ’type ConnectorState struct {
 15вҶ’	Connected   bool   `json:"connected"`
 16вҶ’	ConnectedAt string `json:"connected_at,omitempty"`
 17вҶ’	Account     string `json:"account,omitempty"`
 18вҶ’	Type        string `json:"type"` // "crm" or "email"
 19вҶ’}
 20вҶ’
 21вҶ’// Config is the top-level nurge configuration.
 22вҶ’type Config struct {
 23вҶ’	Version        int                        `json:"version"`
 24вҶ’	CreatedAt      string                     `json:"created_at"`
 25вҶ’	Connectors     map[string]ConnectorState  `json:"connectors"`
 26вҶ’	SetupCompleted bool                       `json:"setup_completed"`
 27вҶ’	Settings       map[string]string          `json:"settings,omitempty"`
 28вҶ’}
 29вҶ’
 30вҶ’// Path returns the path to config.json.
 31вҶ’func Path() string {
 32вҶ’	return configFile
 33вҶ’}
 34вҶ’
 35вҶ’// Default returns a new Config with default values.
 36вҶ’func Default() *Config {
 37вҶ’	return &Config{
 38вҶ’		Version:        1,
 39вҶ’		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 40вҶ’		Connectors:     make(map[string]ConnectorState),
 41вҶ’		SetupCompleted: false,
 42вҶ’	}
 43вҶ’}
 44вҶ’
 45вҶ’// Load reads config from disk.
 46вҶ’func Load() (*Config, error) {
 47вҶ’	data, err := os.ReadFile(configFile)
 48вҶ’	if err != nil {
 49вҶ’		return nil, fmt.Errorf("reading config: %w", err)
 50вҶ’	}
 51вҶ’	var cfg Config
 52вҶ’	if err := json.Unmarshal(data, &cfg); err != nil {
 53вҶ’		return nil, fmt.Errorf("parsing config: %w", err)
 54вҶ’	}
 55вҶ’	if cfg.Connectors == nil {
 56вҶ’		cfg.Connectors = make(map[string]ConnectorState)
 57вҶ’	}
 58вҶ’	return &cfg, nil
 59вҶ’}
 60вҶ’
 61вҶ’// Write saves config to disk.
 62вҶ’func Write(cfg *Config) error {
 63вҶ’	data, err := json.MarshalIndent(cfg, "", "  ")
 64вҶ’	if err != nil {
 65вҶ’		return fmt.Errorf("marshaling config: %w", err)
 66вҶ’	}
 67вҶ’	if err := os.WriteFile(configFile, data, 0644); err != nil {
 68вҶ’		return fmt.Errorf("writing config: %w", err)
 69вҶ’	}
 70вҶ’	return nil
 71вҶ’}
 72вҶ’
 73вҶ’// SetConnector updates a connector in the config and saves.
 74вҶ’func SetConnector(id, connType, account string) error {
 75вҶ’	cfg, err := Load()
 76вҶ’	if err != nil {
 77вҶ’		return err
 78вҶ’	}
 79вҶ’	cfg.Connectors[id] = ConnectorState{
 80вҶ’		Connected:   true,
 81вҶ’		ConnectedAt: time.Now().UTC().Format(time.RFC3339),
 82вҶ’		Account:     account,
 83вҶ’		Type:        connType,
 84вҶ’	}
 85вҶ’	return Write(cfg)
 86вҶ’}
 87вҶ’
 88вҶ’// RemoveConnector removes a connector from config and saves.
 89вҶ’func RemoveConnector(id string) error {
 90вҶ’	cfg, err := Load()
 91вҶ’	if err != nil {
 92вҶ’		return err
 93вҶ’	}
 94вҶ’	delete(cfg.Connectors, id)
 95вҶ’	return Write(cfg)
 96вҶ’}
 97вҶ’
 98вҶ’// Get returns the value for a settings key, or empty string if not set.
 99вҶ’func Get(key string) (string, error) {
100вҶ’	cfg, err := Load()
101вҶ’	if err != nil {
102вҶ’		return "", err
103вҶ’	}
104вҶ’	if cfg.Settings == nil {
105вҶ’		return "", nil
106вҶ’	}
107вҶ’	return cfg.Settings[key], nil
108вҶ’}
109вҶ’
110вҶ’// Set stores a key/value pair in settings and saves the config.
111вҶ’func Set(key, value string) error {
112вҶ’	cfg, err := Load()
113вҶ’	if err != nil {
114вҶ’		return err
115вҶ’	}
116вҶ’	if cfg.Settings == nil {
117вҶ’		cfg.Settings = make(map[string]string)
118вҶ’	}
119вҶ’	cfg.Settings[key] = value
120вҶ’	return Write(cfg)
121вҶ’}
122вҶ’
123вҶ’// SetSetupCompleted sets the top-level setup_completed flag and saves.
124вҶ’// When marking as complete, also removes the global setup skill вҖ” it's no longer needed.
125вҶ’func SetSetupCompleted(completed bool) error {
126вҶ’	cfg, err := Load()
127вҶ’	if err != nil {
128вҶ’		return err
129вҶ’	}
130вҶ’	cfg.SetupCompleted = completed
131вҶ’	if err := Write(cfg); err != nil {
132вҶ’		return err
133вҶ’	}
134вҶ’	if completed {
135вҶ’		removeSetupSkill()
136вҶ’	}
137вҶ’	return nil
138вҶ’}
139вҶ’
140вҶ’// removeSetupSkill deletes the global setup skill directory.
141вҶ’// Graceful вҖ” ignores errors if already removed.
142вҶ’func removeSetupSkill() {
143вҶ’	home, err := os.UserHomeDir()
144вҶ’	if err != nil {
145вҶ’		return
146вҶ’	}
147вҶ’	os.RemoveAll(filepath.Join(home, ".claude", "skills", "nurge-setup"))
148вҶ’}
