 38вҶ’
 39вҶ’var dispatcherCmd = &cobra.Command{
 40вҶ’	Use:   "dispatcher",
 41вҶ’	Short: "Inspect which due sequence tasks are ready to go out",
 42вҶ’}
 43вҶ’
 44вҶ’var dispatcherRunCmd = &cobra.Command{
 45вҶ’	Use:   "run",
 46вҶ’	Short: "Evaluate due sequence tasks against mailbox policy",
 47вҶ’	RunE: func(cmd *cobra.Command, args []string) error {
 48вҶ’		now := timeNow()
 49вҶ’
 50вҶ’		d, err := db.Open()
 51вҶ’		if err != nil {
 52вҶ’			return err
 53вҶ’		}
 54вҶ’		defer d.Close()
 55вҶ’
 56вҶ’		var cfg *project.Config
 57вҶ’		if dispatcherSyncReplies || dispatcherExecute || dispatcherTransportEmail != "" {
 58вҶ’			cfg, err = project.Load()
 59вҶ’			if err != nil {
 60вҶ’				return fmt.Errorf("loading config: %w", err)
 61вҶ’			}
 62вҶ’		}
 63вҶ’
 64вҶ’		transportEmail := strings.TrimSpace(dispatcherTransportEmail)
 65вҶ’		if transportEmail == "" && cfg != nil {
 66вҶ’			if gmail, ok := cfg.Connectors["gmail"]; ok && gmail.Connected {
 67вҶ’				transportEmail = gmail.Account
 68вҶ’			}
 69вҶ’		}
 70вҶ’
 71вҶ’		var gmailService *gm.Service
 72вҶ’		if dispatcherSyncReplies || dispatcherExecute {
 73вҶ’			if cfg == nil {
 74вҶ’				return fmt.Errorf("Gmail config is required for dispatcher execution")
 75вҶ’			}
 76вҶ’			gmail, ok := cfg.Connectors["gmail"]
 77вҶ’			if !ok || !gmail.Connected {
 78вҶ’				return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
 79вҶ’			}
 80вҶ’
 81вҶ’			gmailService, err = email.NewClient("")
 82вҶ’			if err != nil {
 83вҶ’				return fmt.Errorf("connecting to Gmail: %w", err)
 84вҶ’			}
 85вҶ’
 86вҶ’			if dispatcherSyncReplies {
 87вҶ’				if _, err := email.SyncReplies(gmailService, d, gmail.Account, now); err != nil {
 88вҶ’					return err
 89вҶ’				}
 90вҶ’			}
 91вҶ’		}
 92вҶ’
 93вҶ’		if dispatcherExecute && transportEmail == "" {
 94вҶ’			return fmt.Errorf("transport mailbox is required for --execute. Connect Gmail or pass --transport-email")
 95вҶ’		}
 96вҶ’
 97вҶ’		dispatch, err := sequence.ListDispatchTasksForTransport(d, sequence.DispatchOptions{
 98вҶ’			Limit:          dispatcherLimit,
 99вҶ’			Now:            now,
100вҶ’			TransportEmail: transportEmail,
101вҶ’		})
102вҶ’		if err != nil {
103вҶ’			return err
104вҶ’		}
105вҶ’
106вҶ’		var results []dispatcherExecutionResult
107вҶ’		if dispatcherExecute {
108вҶ’			results, err = executeDispatch(gmailService, d, dispatch)
109вҶ’			if err != nil {
110вҶ’				return err
111вҶ’			}
112вҶ’		}
113вҶ’
114вҶ’		if dispatcherFormat == "json" {
115вҶ’			enc := json.NewEncoder(os.Stdout)
116вҶ’			enc.SetIndent("", "  ")
117вҶ’			return enc.Encode(dispatcherRunOutput{
118вҶ’				Queue:   dispatch,
119вҶ’				Results: results,
120вҶ’			})
121вҶ’		}
122вҶ’
123вҶ’		if len(dispatch) == 0 {
124вҶ’			fmt.Println("  вң“ No due tasks in the dispatcher queue")
125вҶ’			return nil
126вҶ’		}
127вҶ’
128вҶ’		for _, item := range dispatch {
129вҶ’			state := "ready"
130вҶ’			if !item.Ready {
131вҶ’				state = "blocked"
132вҶ’			}
133вҶ’			fmt.Printf("  [%s] %s\n", state, dispatchSubject(item))
134вҶ’			fmt.Printf("    task: %s (%s step %d)\n", item.ID, item.SequenceName, item.StepNumber)
135вҶ’			via := item.MailboxEmail
136вҶ’			if item.SelectedMailboxEmail != "" {
137вҶ’				via = item.SelectedMailboxEmail
138вҶ’			}
139вҶ’			fmt.Printf("    to: %s via %s\n", item.ContactEmail, via)
140вҶ’			fmt.Printf("    due: %s\n", shortDate(item.DueAt))
141вҶ’			if dispatcherExecute && item.RenderedBody != "" {
142вҶ’				fmt.Printf("    body: %s\n", preview(item.RenderedBody, 90))
143вҶ’			}
144вҶ’			if item.BlockedReason != "" {
145вҶ’				fmt.Printf("    blocked: %s\n", item.BlockedReason)
146вҶ’			}
147вҶ’		}
148вҶ’
149вҶ’		if dispatcherExecute {
150вҶ’			var sentCount int
151вҶ’			for _, result := range results {
152вҶ’				if result.Status == "sent" {
153вҶ’					sentCount++
154вҶ’				}
155вҶ’			}
156вҶ’			fmt.Printf("\n  вң“ Executed %d due task(s)\n", sentCount)
157вҶ’			for _, result := range results {
158вҶ’				fmt.Printf("    [%s] %s via %s\n", result.Status, result.ContactEmail, result.MailboxEmail)
159вҶ’				if result.Error != "" {
160вҶ’					fmt.Printf("      %s\n", result.Error)
161вҶ’				}
162вҶ’			}
163вҶ’		}
164вҶ’
165вҶ’		return nil
166вҶ’	},
167вҶ’}
168вҶ’
169вҶ’func executeDispatch(srv *gm.Service, d *sql.DB, dispatch []sequence.DispatchTask) ([]dispatcherExecutionResult, error) {
170вҶ’	results := make([]dispatcherExecutionResult, 0, len(dispatch))
171вҶ’	for _, item := range dispatch {
172вҶ’		if !item.Ready {
173вҶ’			continue
174вҶ’		}
175вҶ’
176вҶ’		attemptedAt := timeNow()
177вҶ’		fromAddress := strings.TrimSpace(item.TransportEmail)
178вҶ’		if fromAddress == "" {
179вҶ’			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
180вҶ’		}
181вҶ’		if fromAddress == "" {
182вҶ’			results = append(results, dispatcherExecutionResult{
183вҶ’				TaskID:       item.ID,
184вҶ’				ContactEmail: item.ContactEmail,
185вҶ’				MailboxEmail: item.SelectedMailboxEmail,
186вҶ’				Status:       "failed",
187вҶ’				Error:        "no transport address available for task",
188вҶ’			})
189вҶ’			continue
190вҶ’		}
191вҶ’
192вҶ’		sent, err := email.Send(srv, fromAddress, email.SendOptions{
193вҶ’			To:       item.ContactEmail,
194вҶ’			Subject:  dispatchSubject(item),
195вҶ’			Body:     item.RenderedBody,
196вҶ’			ThreadID: item.ThreadID,
197вҶ’		})
198вҶ’		if err != nil {
199вҶ’			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
200вҶ’				return results, markErr
201вҶ’			}
202вҶ’			results = append(results, dispatcherExecutionResult{
203вҶ’				TaskID:       item.ID,
204вҶ’				ContactEmail: item.ContactEmail,
205вҶ’				MailboxEmail: item.SelectedMailboxEmail,
206вҶ’				Status:       "failed",
207вҶ’				Error:        err.Error(),
208вҶ’			})
209вҶ’			continue
210вҶ’		}
211вҶ’
212вҶ’		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
213вҶ’			return results, err
214вҶ’		}
215вҶ’		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
216вҶ’			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
217вҶ’		}
218вҶ’		if err := email.StoreEmail(d, &email.RawMessage{
219вҶ’			ID:        sent.MessageID,
220вҶ’			Source:    "gmail",
221вҶ’			Direction: "outbound",
222вҶ’			ThreadID:  sent.ThreadID,
223вҶ’			Subject:   dispatchSubject(item),
224вҶ’			FromEmail: fromAddress,
225вҶ’			ToEmails:  recipientsJSON(item.ContactEmail),
226вҶ’			Date:      attemptedAt.UTC().Format(time.RFC3339),
227вҶ’			Labels:    `["SENT"]`,
228вҶ’		}); err != nil {
229вҶ’			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
230вҶ’		}
231вҶ’		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
232вҶ’			TaskID:    item.ID,
233вҶ’			ThreadID:  sent.ThreadID,
234вҶ’			MessageID: sent.MessageID,
235вҶ’			MailboxID: item.SelectedMailboxID,
236вҶ’			SentAt:    attemptedAt,
237вҶ’		}); err != nil {
238вҶ’			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
239вҶ’		}
240вҶ’
241вҶ’		results = append(results, dispatcherExecutionResult{
242вҶ’			TaskID:       item.ID,
243вҶ’			ContactEmail: item.ContactEmail,
244вҶ’			MailboxEmail: item.SelectedMailboxEmail,
245вҶ’			MessageID:    sent.MessageID,
246вҶ’			Status:       "sent",
247вҶ’		})
248вҶ’	}
249вҶ’	return results, nil
250вҶ’}
