261вҶ’func dispatchSubject(item sequence.DispatchTask) string {
262вҶ’	if strings.TrimSpace(item.RenderedSubject) != "" {
263вҶ’		return strings.TrimSpace(item.RenderedSubject)
264вҶ’	}
265вҶ’	return strings.TrimSpace(item.Subject)
266вҶ’}
