  1вҶ’package email
  2вҶ’
  3вҶ’import (
  4вҶ’	"database/sql"
  5вҶ’	"encoding/json"
  6вҶ’	"fmt"
  7вҶ’	"strings"
  8вҶ’	"time"
  9вҶ’
 10вҶ’	gm "google.golang.org/api/gmail/v1"
 11вҶ’)
 12вҶ’
 13вҶ’type RawMessage struct {
 14вҶ’	ID          string
 15вҶ’	Source      string
 16вҶ’	Direction   string
 17вҶ’	ThreadID    string
 18вҶ’	Subject     string
 19вҶ’	FromEmail   string
 20вҶ’	ToEmails    string // JSON array
 21вҶ’	CcEmails    string // JSON array
 22вҶ’	Date        string
 23вҶ’	Snippet     string
 24вҶ’	BodyPreview string
 25вҶ’	Labels      string // JSON array
 26вҶ’}
 27вҶ’
 28вҶ’type SyncResult struct {
 29вҶ’	Fetched  int
 30вҶ’	Stored   int
 31вҶ’	Cursor   string
 32вҶ’	Duration time.Duration
 33вҶ’}
 34вҶ’
 35вҶ’func Sync(srv *gm.Service, d *sql.DB) (*SyncResult, error) {
 36вҶ’	start := time.Now()
 37вҶ’	result := &SyncResult{}
 38вҶ’
 39вҶ’	var cursor string
 40вҶ’	d.QueryRow("SELECT sync_cursor FROM connectors WHERE id = 'gmail'").Scan(&cursor)
 41вҶ’
 42вҶ’	query := "in:sent"
 43вҶ’	if cursor == "" {
 44вҶ’		since := time.Now().AddDate(0, 0, -90).Format("2006/01/02")
 45вҶ’		query += " after:" + since
 46вҶ’	}
 47вҶ’
 48вҶ’	var pageToken string
 49вҶ’	for {
 50вҶ’		req := srv.Users.Messages.List("me").Q(query).MaxResults(100)
 51вҶ’		if pageToken != "" {
 52вҶ’			req = req.PageToken(pageToken)
 53вҶ’		}
 54вҶ’
 55вҶ’		resp, err := req.Do()
 56вҶ’		if err != nil {
 57вҶ’			return result, fmt.Errorf("listing messages: %w", err)
 58вҶ’		}
 59вҶ’
 60вҶ’		for _, msg := range resp.Messages {
 61вҶ’			result.Fetched++
 62вҶ’
 63вҶ’			if cursor != "" {
 64вҶ’				var exists int
 65вҶ’				d.QueryRow("SELECT 1 FROM emails WHERE id = ?", msg.Id).Scan(&exists)
 66вҶ’				if exists == 1 {
 67вҶ’					continue
 68вҶ’				}
 69вҶ’			}
 70вҶ’
 71вҶ’			full, err := srv.Users.Messages.Get("me", msg.Id).Format("metadata").
 72вҶ’				MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 73вҶ’			if err != nil {
 74вҶ’				fmt.Printf("  warning: skipping message %s: %v\n", msg.Id, err)
 75вҶ’				continue
 76вҶ’			}
 77вҶ’
 78вҶ’			email := parseMessage(full)
 79вҶ’			if err := StoreEmail(d, email); err != nil {
 80вҶ’				fmt.Printf("  warning: storing message %s: %v\n", msg.Id, err)
 81вҶ’				continue
 82вҶ’			}
 83вҶ’			result.Stored++
 84вҶ’		}
 85вҶ’
 86вҶ’		pageToken = resp.NextPageToken
 87вҶ’		if pageToken == "" {
 88вҶ’			break
 89вҶ’		}
 90вҶ’	}
 91вҶ’
 92вҶ’	result.Cursor = time.Now().UTC().Format(time.RFC3339)
 93вҶ’	result.Duration = time.Since(start)
 94вҶ’
 95вҶ’	d.Exec(
 96вҶ’		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
 97вҶ’		 VALUES ('gmail', 'email', ?, ?, ?)
 98вҶ’		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
 99вҶ’		result.Cursor, result.Cursor, result.Stored,
100вҶ’		result.Cursor, result.Cursor, result.Stored,
101вҶ’	)
102вҶ’
103вҶ’	return result, nil
104вҶ’}
