106вҶ’func StoreEmail(d *sql.DB, e *RawMessage) error {
107вҶ’	source := e.Source
108вҶ’	if source == "" {
109вҶ’		source = "gmail"
110вҶ’	}
111вҶ’	direction := e.Direction
112вҶ’	if direction == "" {
113вҶ’		direction = "outbound"
114вҶ’	}
115вҶ’
116вҶ’	isNewMessage := true
117вҶ’	var existing int
118вҶ’	err := d.QueryRow(`SELECT 1 FROM emails WHERE id = ?`, e.ID).Scan(&existing)
119вҶ’	if err == nil {
120вҶ’		isNewMessage = false
121вҶ’	} else if err != nil && err != sql.ErrNoRows {
122вҶ’		return err
123вҶ’	}
124вҶ’
125вҶ’	_, err = d.Exec(`
126вҶ’		INSERT INTO emails (id, source, direction, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
127вҶ’		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
128вҶ’		ON CONFLICT(id) DO UPDATE SET
129вҶ’			source = excluded.source,
130вҶ’			direction = excluded.direction,
131вҶ’			subject = excluded.subject,
132вҶ’			snippet = excluded.snippet,
133вҶ’			body_preview = excluded.body_preview,
134вҶ’			labels = excluded.labels,
135вҶ’			synced_at = datetime('now')`,
136вҶ’		e.ID, source, direction, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
137вҶ’		e.Date, e.Snippet, e.BodyPreview, e.Labels,
138вҶ’	)
139вҶ’	if err != nil {
140вҶ’		return err
141вҶ’	}
142вҶ’	return upsertContactsForMessage(d, source, direction, e, isNewMessage)
143вҶ’}
