145вҶ’func parseMessage(msg *gm.Message) *RawMessage {
146вҶ’	e := &RawMessage{
147вҶ’		ID:        msg.Id,
148вҶ’		Source:    "gmail",
149вҶ’		Direction: "outbound",
150вҶ’		ThreadID:  msg.ThreadId,
151вҶ’		Snippet:   msg.Snippet,
152вҶ’		CcEmails:  "[]",
153вҶ’		ToEmails:  "[]",
154вҶ’		Labels:    "[]",
155вҶ’	}
156вҶ’
157вҶ’	for _, h := range msg.Payload.Headers {
158вҶ’		switch h.Name {
159вҶ’		case "Subject":
160вҶ’			e.Subject = h.Value
161вҶ’		case "From":
162вҶ’			e.FromEmail = extractEmail(h.Value)
163вҶ’		case "To":
164вҶ’			e.ToEmails = emailsToJSON(h.Value)
165вҶ’		case "Cc":
166вҶ’			e.CcEmails = emailsToJSON(h.Value)
167вҶ’		case "Date":
168вҶ’			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
169вҶ’				e.Date = t.UTC().Format(time.RFC3339)
170вҶ’			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
171вҶ’				e.Date = t.UTC().Format(time.RFC3339)
172вҶ’			} else {
173вҶ’				e.Date = h.Value
174вҶ’			}
175вҶ’		}
176вҶ’	}
177вҶ’
178вҶ’	if len(msg.LabelIds) > 0 {
179вҶ’		labelsJSON, _ := json.Marshal(msg.LabelIds)
180вҶ’		e.Labels = string(labelsJSON)
181вҶ’	}
182вҶ’
183вҶ’	return e
184вҶ’}
