186вҶ’func upsertContactsForMessage(d *sql.DB, source, direction string, e *RawMessage, incrementCount bool) error {
187вҶ’	timestamp := e.Date
188вҶ’	if direction == "inbound" {
189вҶ’		return upsertContact(d, source, e.FromEmail, timestamp, incrementCount)
190вҶ’	}
191вҶ’
192вҶ’	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
193вҶ’	for _, recipient := range recipients {
194вҶ’		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
195вҶ’			return err
196вҶ’		}
197вҶ’	}
198вҶ’	return nil
199вҶ’}
200вҶ’
201вҶ’func upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
202вҶ’	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
203вҶ’	if emailAddress == "" {
204вҶ’		return nil
205вҶ’	}
206вҶ’	domain := ""
207вҶ’	parts := strings.SplitN(emailAddress, "@", 2)
208вҶ’	if len(parts) == 2 {
209вҶ’		domain = parts[1]
210вҶ’	}
211вҶ’
212вҶ’	_, err := d.Exec(`
213вҶ’		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
214вҶ’		VALUES (?, ?, ?, ?, ?, 1, ?)
215вҶ’		ON CONFLICT(source, email) DO UPDATE SET
216вҶ’			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
217вҶ’			last_activity_at = CASE
218вҶ’				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
219вҶ’				ELSE contacts.last_activity_at
220вҶ’			END,
221вҶ’			last_emailed_at = CASE
222вҶ’				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
223вҶ’				ELSE contacts.last_emailed_at
224вҶ’			END,
225вҶ’			email_count = contacts.email_count + ?,
226вҶ’			updated_at = datetime('now')`,
227вҶ’		"contact:"+source+":"+emailAddress, source, emailAddress, domain, activityAt, activityAt, boolToInt(incrementCount),
228вҶ’	)
229вҶ’	return err
230вҶ’}
231вҶ’
232вҶ’func boolToInt(value bool) int {
233вҶ’	if value {
234вҶ’		return 1
235вҶ’	}
236вҶ’	return 0
237вҶ’}
238вҶ’
239вҶ’func extractEmail(header string) string {
240вҶ’	if i := strings.Index(header, "<"); i != -1 {
241вҶ’		if j := strings.Index(header, ">"); j != -1 {
242вҶ’			return header[i+1 : j]
243вҶ’		}
244вҶ’	}
245вҶ’	return strings.TrimSpace(header)
246вҶ’}
247вҶ’
248вҶ’func emailsToJSON(header string) string {
249вҶ’	if header == "" {
250вҶ’		return "[]"
251вҶ’	}
252вҶ’	parts := strings.Split(header, ",")
253вҶ’	emails := make([]string, 0, len(parts))
254вҶ’	for _, p := range parts {
255вҶ’		emails = append(emails, extractEmail(p))
256вҶ’	}
257вҶ’	data, _ := json.Marshal(emails)
258вҶ’	return string(data)
259вҶ’}
