  1вҶ’package email
  2вҶ’
  3вҶ’import (
  4вҶ’	"database/sql"
  5вҶ’	"strings"
  6вҶ’	"time"
  7вҶ’
  8вҶ’	gm "google.golang.org/api/gmail/v1"
  9вҶ’
 10вҶ’	"github.com/usenurge/nurgesh/internal/sequence"
 11вҶ’)
 12вҶ’
 13вҶ’type ReplySyncResult struct {
 14вҶ’	ThreadsScanned  int `json:"threads_scanned"`
 15вҶ’	MessagesScanned int `json:"messages_scanned"`
 16вҶ’	RepliesRecorded int `json:"replies_recorded"`
 17вҶ’	Paused          int `json:"paused"`
 18вҶ’	Stopped         int `json:"stopped"`
 19вҶ’}
 20вҶ’
 21вҶ’func SyncReplies(srv *gm.Service, d *sql.DB, mailboxEmail string, now time.Time) (*ReplySyncResult, error) {
 22вҶ’	if now.IsZero() {
 23вҶ’		now = time.Now()
 24вҶ’	}
 25вҶ’
 26вҶ’	enrollments, err := sequence.ListEnrollments(d, sequence.StatusActive, 0)
 27вҶ’	if err != nil {
 28вҶ’		return nil, err
 29вҶ’	}
 30вҶ’
 31вҶ’	result := &ReplySyncResult{}
 32вҶ’	for _, enrollment := range enrollments {
 33вҶ’		if enrollment.ThreadID == "" {
 34вҶ’			continue
 35вҶ’		}
 36вҶ’		if mailboxEmail != "" && !strings.EqualFold(mailboxEmail, enrollment.MailboxEmail) {
 37вҶ’			continue
 38вҶ’		}
 39вҶ’
 40вҶ’		thread, err := srv.Users.Threads.Get("me", enrollment.ThreadID).Format("metadata").
 41вҶ’			MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 42вҶ’		if err != nil {
 43вҶ’			return nil, err
 44вҶ’		}
 45вҶ’		result.ThreadsScanned++
 46вҶ’
 47вҶ’		watermark := latestKnownThreadTime(enrollment)
 48вҶ’		for i := 0; i < len(thread.Messages); i++ {
 49вҶ’			result.MessagesScanned++
 50вҶ’			raw := parseMessage(thread.Messages[i])
 51вҶ’			raw.Direction = inferDirection(raw, enrollment.MailboxEmail)
 52вҶ’			if raw.Direction != "inbound" {
 53вҶ’				continue
 54вҶ’			}
 55вҶ’
 56вҶ’			occurredAt, ok := parseStoredEmailTime(raw.Date)
 57вҶ’			if !ok {
 58вҶ’				continue
 59вҶ’			}
 60вҶ’			if !watermark.IsZero() && !occurredAt.After(watermark) {
 61вҶ’				continue
 62вҶ’			}
 63вҶ’
 64вҶ’			raw.ThreadID = enrollment.ThreadID
 65вҶ’			raw.Direction = "inbound"
 66вҶ’			if err := StoreEmail(d, raw); err != nil {
 67вҶ’				return nil, err
 68вҶ’			}
 69вҶ’
 70вҶ’			reply, err := sequence.RecordReply(d, sequence.ReplyOptions{
 71вҶ’				EnrollmentID:   enrollment.ID,
 72вҶ’				MailboxID:      enrollment.MailboxID,
 73вҶ’				ThreadID:       enrollment.ThreadID,
 74вҶ’				MessageID:      raw.ID,
 75вҶ’				ContactEmail:   raw.FromEmail,
 76вҶ’				Classification: classifyReply(raw.FromEmail, raw.Subject, raw.Snippet),
 77вҶ’				Subject:        raw.Subject,
 78вҶ’				Snippet:        raw.Snippet,
 79вҶ’				OccurredAt:     occurredAt,
 80вҶ’			})
 81вҶ’			if err != nil {
 82вҶ’				return nil, err
 83вҶ’			}
 84вҶ’
 85вҶ’			result.RepliesRecorded++
 86вҶ’			if reply.Classification == "not_interested" || reply.Classification == "unsubscribe" || reply.Classification == "bounced" {
 87вҶ’				result.Stopped++
 88вҶ’			} else {
 89вҶ’				result.Paused++
 90вҶ’			}
 91вҶ’		}
 92вҶ’	}
 93вҶ’
 94вҶ’	return result, nil
 95вҶ’}
 96вҶ’
 97вҶ’func classifyReply(fromEmail, subject, snippet string) string {
 98вҶ’	text := strings.ToLower(strings.TrimSpace(fromEmail) + "\n" + subject + "\n" + snippet)
 99вҶ’	switch {
100вҶ’	case containsAny(text, "mailer-daemon", "postmaster", "delivery status notification", "undeliverable", "message blocked", "delivery has failed"):
101вҶ’		return "bounced"
102вҶ’	case containsAny(text, "out of office", "out-of-office", "automatic reply", "auto-reply", "ooo", "away until"):
103вҶ’		return "out_of_office"
104вҶ’	case containsAny(text, "unsubscribe", "stop emailing", "do not contact"):
105вҶ’		return "unsubscribe"
106вҶ’	case containsAny(text, "not interested", "no interest", "no thanks", "remove me"):
107вҶ’		return "not_interested"
108вҶ’	case containsAny(text, "yes", "interested", "sounds good", "let's chat", "let us chat", "worth a look", "happy to talk"):
109вҶ’		return "interested"
110вҶ’	case containsAny(text, "reach out to", "talk to", "speak with", "contact ") && strings.Contains(text, "@"):
111вҶ’		return "referral"
112вҶ’	default:
113вҶ’		return "replied"
