400вҶ’func CanSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
401вҶ’	sendType = NormalizeSendType(sendType)
402вҶ’	if sendType == SendTypeManual {
403вҶ’		return nil
404вҶ’	}
405вҶ’	if now.IsZero() {
406вҶ’		now = time.Now()
407вҶ’	}
408вҶ’
409вҶ’	mailbox, usage, err := mailboxAndUsage(d, mailboxID, now)
410вҶ’	if err != nil {
411вҶ’		return err
412вҶ’	}
413вҶ’	if mailbox.Status != "active" {
414вҶ’		return fmt.Errorf("mailbox %s is %s", mailbox.Email, mailbox.Status)
415вҶ’	}
416вҶ’	if mailbox.ReputationScore > 0 && mailbox.ReputationScore < 40 {
417вҶ’		return fmt.Errorf("mailbox %s reputation is too low (%d)", mailbox.Email, mailbox.ReputationScore)
418вҶ’	}
419вҶ’	if !withinSendWindow(*mailbox, now) {
420вҶ’		return fmt.Errorf("mailbox %s is outside its send window (%s %02d:00-%02d:00)", mailbox.Email, mailbox.SendWindowTimezone, mailbox.SendWindowStartHour, mailbox.SendWindowEndHour)
421вҶ’	}
422вҶ’	if mailbox.LastBounceAt != "" && sendType == SendTypeFirstTouch {
423вҶ’		if bouncedAt, err := time.Parse(time.RFC3339, mailbox.LastBounceAt); err == nil && now.UTC().Before(bouncedAt.Add(24*time.Hour)) {
424вҶ’			return fmt.Errorf("mailbox %s is cooling off after a recent bounce until %s", mailbox.Email, bouncedAt.Add(24*time.Hour).Format(time.RFC3339))
425вҶ’		}
426вҶ’	}
427вҶ’
428вҶ’	firstTouchCap, followUpCap, replyCap := effectiveCaps(*mailbox)
429вҶ’
430вҶ’	switch sendType {
431вҶ’	case SendTypeFirstTouch:
432вҶ’		if firstTouchCap > 0 && usage.FirstTouchesSent >= firstTouchCap {
433вҶ’			return fmt.Errorf("mailbox %s has reached its first-touch daily cap (%d/%d)", mailbox.Email, usage.FirstTouchesSent, firstTouchCap)
434вҶ’		}
435вҶ’	case SendTypeFollowUp:
436вҶ’		if followUpCap > 0 && usage.FollowUpsSent >= followUpCap {
437вҶ’			return fmt.Errorf("mailbox %s has reached its follow-up daily cap (%d/%d)", mailbox.Email, usage.FollowUpsSent, followUpCap)
438вҶ’		}
439вҶ’	case SendTypeReply:
440вҶ’		if replyCap > 0 && usage.RepliesSent >= replyCap {
441вҶ’			return fmt.Errorf("mailbox %s has reached its reply daily cap (%d/%d)", mailbox.Email, usage.RepliesSent, replyCap)
442вҶ’		}
443вҶ’	}
444вҶ’
445вҶ’	if mailbox.MinGapMinutes > 0 {
446вҶ’		lastSentAt, err := latestMailboxOutboundAt(d, effectiveTransportEmail(*mailbox))
447вҶ’		if err != nil {
448вҶ’			return err
449вҶ’		}
450вҶ’		if !lastSentAt.IsZero() {
451вҶ’			nextAllowed := lastSentAt.Add(time.Duration(mailbox.MinGapMinutes) * time.Minute)
452вҶ’			if now.UTC().Before(nextAllowed) {
453вҶ’				return fmt.Errorf("mailbox %s is cooling down until %s", mailbox.Email, nextAllowed.Format(time.RFC3339))
454вҶ’			}
455вҶ’		}
456вҶ’	}
457вҶ’
458вҶ’	return nil
459вҶ’}
