136вҶ’			if item.SelectedMailboxEmail != "" {
137вҶ’				via = item.SelectedMailboxEmail
138вҶ’			}
139вҶ’			fmt.Printf("    to: %s via %s\n", item.ContactEmail, via)
140вҶ’			fmt.Printf("    due: %s\n", shortDate(item.DueAt))
141вҶ’			if dispatcherExecute && item.RenderedBody != "" {
142вҶ’				fmt.Printf("    body: %s\n", preview(item.RenderedBody, 90))
143вҶ’			}
144вҶ’			if item.BlockedReason != "" {
145вҶ’				fmt.Printf("    blocked: %s\n", item.BlockedReason)
146вҶ’			}
147вҶ’		}
148вҶ’
149вҶ’		if dispatcherExecute {
150вҶ’			var sentCount int
151вҶ’			for _, result := range results {
152вҶ’				if result.Status == "sent" {
153вҶ’					sentCount++
154вҶ’				}
155вҶ’			}
156вҶ’			fmt.Printf("\n  вң“ Executed %d due task(s)\n", sentCount)
157вҶ’			for _, result := range results {
158вҶ’				fmt.Printf("    [%s] %s via %s\n", result.Status, result.ContactEmail, result.MailboxEmail)
159вҶ’				if result.Error != "" {
160вҶ’					fmt.Printf("      %s\n", result.Error)
161вҶ’				}
162вҶ’			}
163вҶ’		}
164вҶ’
165вҶ’		return nil
166вҶ’	},
167вҶ’}
