169вҶ’func executeDispatch(srv *gm.Service, d *sql.DB, dispatch []sequence.DispatchTask) ([]dispatcherExecutionResult, error) {
170вҶ’	results := make([]dispatcherExecutionResult, 0, len(dispatch))
171вҶ’	for _, item := range dispatch {
172вҶ’		if !item.Ready {
173вҶ’			continue
174вҶ’		}
175вҶ’
176вҶ’		attemptedAt := timeNow()
177вҶ’		fromAddress := strings.TrimSpace(item.TransportEmail)
178вҶ’		if fromAddress == "" {
179вҶ’			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
180вҶ’		}
181вҶ’		if fromAddress == "" {
182вҶ’			results = append(results, dispatcherExecutionResult{
183вҶ’				TaskID:       item.ID,
184вҶ’				ContactEmail: item.ContactEmail,
185вҶ’				MailboxEmail: item.SelectedMailboxEmail,
186вҶ’				Status:       "failed",
187вҶ’				Error:        "no transport address available for task",
188вҶ’			})
189вҶ’			continue
190вҶ’		}
191вҶ’
192вҶ’		sent, err := email.Send(srv, fromAddress, email.SendOptions{
193вҶ’			To:       item.ContactEmail,
194вҶ’			Subject:  dispatchSubject(item),
195вҶ’			Body:     item.RenderedBody,
196вҶ’			ThreadID: item.ThreadID,
197вҶ’		})
198вҶ’		if err != nil {
199вҶ’			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
200вҶ’				return results, markErr
201вҶ’			}
202вҶ’			results = append(results, dispatcherExecutionResult{
203вҶ’				TaskID:       item.ID,
204вҶ’				ContactEmail: item.ContactEmail,
205вҶ’				MailboxEmail: item.SelectedMailboxEmail,
206вҶ’				Status:       "failed",
207вҶ’				Error:        err.Error(),
208вҶ’			})
209вҶ’			continue
210вҶ’		}
211вҶ’
212вҶ’		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
213вҶ’			return results, err
214вҶ’		}
215вҶ’		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
216вҶ’			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
217вҶ’		}
218вҶ’		if err := email.StoreEmail(d, &email.RawMessage{
219вҶ’			ID:        sent.MessageID,
220вҶ’			Source:    "gmail",
221вҶ’			Direction: "outbound",
222вҶ’			ThreadID:  sent.ThreadID,
223вҶ’			Subject:   dispatchSubject(item),
224вҶ’			FromEmail: fromAddress,
225вҶ’			ToEmails:  recipientsJSON(item.ContactEmail),
226вҶ’			Date:      attemptedAt.UTC().Format(time.RFC3339),
227вҶ’			Labels:    `["SENT"]`,
228вҶ’		}); err != nil {
229вҶ’			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
230вҶ’		}
231вҶ’		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
232вҶ’			TaskID:    item.ID,
233вҶ’			ThreadID:  sent.ThreadID,
234вҶ’			MessageID: sent.MessageID,
235вҶ’			MailboxID: item.SelectedMailboxID,
236вҶ’			SentAt:    attemptedAt,
237вҶ’		}); err != nil {
238вҶ’			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
239вҶ’		}
240вҶ’
241вҶ’		results = append(results, dispatcherExecutionResult{
242вҶ’			TaskID:       item.ID,
243вҶ’			ContactEmail: item.ContactEmail,
244вҶ’			MailboxEmail: item.SelectedMailboxEmail,
245вҶ’			MessageID:    sent.MessageID,
246вҶ’			Status:       "sent",
247вҶ’		})
248вҶ’	}
249вҶ’	return results, nil
250вҶ’}
