252вҶ’func preview(body string, limit int) string {
253вҶ’	body = strings.TrimSpace(body)
254вҶ’	body = strings.ReplaceAll(body, "\n", " ")
255вҶ’	if limit <= 0 || len(body) <= limit {
256вҶ’		return body
257вҶ’	}
258вҶ’	return body[:limit-1] + "вҖҰ"
259вҶ’}
260вҶ’
261вҶ’func dispatchSubject(item sequence.DispatchTask) string {
262вҶ’	if strings.TrimSpace(item.RenderedSubject) != "" {
263вҶ’		return strings.TrimSpace(item.RenderedSubject)
264вҶ’	}
265вҶ’	return strings.TrimSpace(item.Subject)
266вҶ’}
