225вҶ’func recipientsJSON(raw string) string {
226вҶ’	raw = strings.TrimSpace(raw)
227вҶ’	if raw == "" {
228вҶ’		return "[]"
229вҶ’	}
230вҶ’	parts := strings.Split(raw, ",")
231вҶ’	recipients := make([]string, 0, len(parts))
232вҶ’	for _, part := range parts {
233вҶ’		part = strings.TrimSpace(part)
234вҶ’		if part != "" {
235вҶ’			recipients = append(recipients, part)
236вҶ’		}
237вҶ’	}
238вҶ’	data, _ := json.Marshal(recipients)
239вҶ’	return string(data)
240вҶ’}
