  1вҶ’package account
  2вҶ’
  3вҶ’import (
  4вҶ’	"bytes"
  5вҶ’	"encoding/json"
  6вҶ’	"errors"
  7вҶ’	"fmt"
  8вҶ’	"io"
  9вҶ’	"net/http"
 10вҶ’	"time"
 11вҶ’)
 12вҶ’
 13вҶ’// User represents an authenticated Nurge user.
 14вҶ’type User struct {
 15вҶ’	Email string `json:"email"`
 16вҶ’	Name  string `json:"name"`
 17вҶ’}
 18вҶ’
 19вҶ’// ConvexClient calls Convex HTTP actions for auth operations.
 20вҶ’type ConvexClient struct {
 21вҶ’	baseURL    string
 22вҶ’	httpClient *http.Client
 23вҶ’}
 24вҶ’
 25вҶ’// NewConvexClient creates a client for the given Convex site URL.
 26вҶ’func NewConvexClient(baseURL string) *ConvexClient {
 27вҶ’	return &ConvexClient{
 28вҶ’		baseURL: baseURL,
 29вҶ’		httpClient: &http.Client{
 30вҶ’			Timeout: 10 * time.Second,
 31вҶ’		},
 32вҶ’	}
 33вҶ’}
 34вҶ’
 35вҶ’type validateResponse struct {
 36вҶ’	Valid bool  `json:"valid"`
 37вҶ’	User  *User `json:"user,omitempty"`
 38вҶ’}
 39вҶ’
 40вҶ’// ErrTokenInvalid is returned when the server confirms the token is invalid.
 41вҶ’// This is distinct from network errors, which may allow grace period fallback.
 42вҶ’var ErrTokenInvalid = errors.New("token is invalid or expired")
 43вҶ’
 44вҶ’// ValidateToken checks a token against the Convex backend.
 45вҶ’// Returns ErrTokenInvalid if server says token is invalid.
 46вҶ’// Returns a different error for network/parse failures.
 47вҶ’func (c *ConvexClient) ValidateToken(token string) (*User, error) {
 48вҶ’	body, err := json.Marshal(map[string]string{"token": token})
 49вҶ’	if err != nil {
 50вҶ’		return nil, fmt.Errorf("marshaling request: %w", err)
 51вҶ’	}
 52вҶ’	resp, err := c.httpClient.Post(
 53вҶ’		c.baseURL+"/api/validate-token",
 54вҶ’		"application/json",
 55вҶ’		bytes.NewReader(body),
 56вҶ’	)
 57вҶ’	if err != nil {
 58вҶ’		return nil, fmt.Errorf("calling validate-token: %w", err)
 59вҶ’	}
 60вҶ’	defer resp.Body.Close()
 61вҶ’
 62вҶ’	data, err := io.ReadAll(resp.Body)
 63вҶ’	if err != nil {
 64вҶ’		return nil, fmt.Errorf("reading response: %w", err)
 65вҶ’	}
 66вҶ’
 67вҶ’	var result validateResponse
 68вҶ’	if err := json.Unmarshal(data, &result); err != nil {
 69вҶ’		return nil, fmt.Errorf("parsing response: %w", err)
 70вҶ’	}
 71вҶ’
 72вҶ’	if !result.Valid {
 73вҶ’		return nil, ErrTokenInvalid
 74вҶ’	}
 75вҶ’	return result.User, nil
 76вҶ’}
 77вҶ’
 78вҶ’type exchangeResponse struct {
 79вҶ’	Token string `json:"token"`
 80вҶ’	Email string `json:"email"`
 81вҶ’	Name  string `json:"name"`
 82вҶ’	Error string `json:"error,omitempty"`
 83вҶ’}
 84вҶ’
 85вҶ’// ExchangeCode exchanges a one-time auth code for an API token.
 86вҶ’func (c *ConvexClient) ExchangeCode(code string) (*exchangeResponse, error) {
 87вҶ’	body, _ := json.Marshal(map[string]string{"code": code})
 88вҶ’	resp, err := c.httpClient.Post(
 89вҶ’		c.baseURL+"/api/exchange-code",
 90вҶ’		"application/json",
 91вҶ’		bytes.NewReader(body),
 92вҶ’	)
 93вҶ’	if err != nil {
 94вҶ’		return nil, fmt.Errorf("calling exchange-code: %w", err)
 95вҶ’	}
 96вҶ’	defer resp.Body.Close()
 97вҶ’
 98вҶ’	data, err := io.ReadAll(resp.Body)
 99вҶ’	if err != nil {
100вҶ’		return nil, fmt.Errorf("reading response: %w", err)
101вҶ’	}
